trigger.body:
	vCheck NUMBER;

BEGIN

	IF AD_isTriggerEnabled() = 'N' THEN RETURN;END IF;

	IF UPDATING THEN

		SELECT COUNT(*) INTO vCheck FROM sinvmin_square_bill
		WHERE c_orderline_id = :NEW.c_orderline_id AND (c_invoiceline_id IS NOT NULL OR m_inoutline_id IS NOT NULL);

		IF vCheck = 0 THEN
			UPDATE sinvmin_square_bill SET qty = :NEW.qtyordered WHERE c_orderline_id = :NEW.c_orderline_id;
		END IF;

	END IF;

	IF DELETING THEN

		DELETE FROM sinvmin_square_bill
		WHERE ad_table_id = '259' AND c_orderline_id = :OLD.c_orderline_id;

		RETURN OLD;

	END IF;

	END SINVMIN_SQUAREBILL_ORDER_TRG
